const config = $('Client Config').item.json;
const today = new Date().toDateString();

const body = `Good morning ${config.recipient_name},

Thursday Engagement Checklist — ${today}

✅ LINKEDIN ENGAGEMENT (15 min)
   • Comment thoughtfully on 10–15 posts from ICP contacts
     Target titles: ${config.icp_titles}
   • Check connection request acceptances — send connect notes to accepted
   • Reply to any DMs received this week
   • Note anyone who liked or commented on your recent posts

✅ WARM LEAD FOLLOW-UP
   • Open HubSpot and filter by 'Last activity: this week'
   • Send a personal note to anyone who opened an outreach email
   • Move any 'CONNECTED' leads to next pipeline stage
   • Log any conversations or signals as HubSpot notes

✅ CONTENT
   • Publish your Thursday LinkedIn post if scheduled
   • Engage with posts using these topics: ${config.content_topics}

✅ PIPELINE REVIEW PREP
   • Tag any new buying signals discovered this week before Friday report
   • Update hs_lead_status for any leads whose status has changed

— LeadGen System`;

return [{
  json: {
    to: config.recipient_email,
    subject: '[LeadGen] Thursday Engagement Checklist',
    body,
    reply_to: config.recipient_email
  }
}];
